mapper.select:
SELECT t.id,t.equity_index, t.equity_index_name, t.date, t.dividend_yield FROM equity_index_dividend_yield_daily t
 JOIN (
  SELECT equity_index, MAX(`date`) AS max_date
  FROM equity_index_dividend_yield_daily
  GROUP BY equity_index
) m ON t.equity_index = m.equity_index AND t.`date` = m.max_date order by t.id;
